import React from 'react';
import {
  Box,
  Paper,
  Button,
  // Checkbox,
  // FormControlLabel,
  IconButton,
  InputAdornment,
  TextField,
  Typography,
  CircularProgress,
  Alert,
} from '@mui/material';
import { 
  Visibility, 
  VisibilityOff, 
  LockOutlined, 
  PersonOutline,
  Login as LoginIcon,
} from '@mui/icons-material';
import { useForm } from 'react-hook-form';
import Link from '../../../../components/Link';
import { LoginFormInputs } from '../../types';
import { request } from '../../../../utils/request';
import { useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../../../../contexts/AuthContext';

const LoginForm: React.FC = () => {
  const [showPassword, setShowPassword] = React.useState(false);
  const [loading, setLoading] = React.useState(false);
  const [loginError, setLoginError] = React.useState<string>('');
  // const [rememberMe, setRememberMe] = useState(false);
  const navigate = useNavigate();
  const { login } = useAuth();

  const {
    register,
    handleSubmit,
    reset,
    formState: { errors },
  } = useForm<LoginFormInputs>({
    defaultValues: {
      identifier: '',
      password: '',
    },
  });

  const onSubmit = async (data: LoginFormInputs, event?: React.BaseSyntheticEvent) => {
    event?.preventDefault();
    if (loading) return;

    try {
      setLoading(true);
      setLoginError('');

      const response = await request({
        url: "auth/login",
        method: "post",
        data: data
      });

      if (response.status === "success") {
        const loginUser = {
          userId: response.user?._id,
          name: response.user?.name,
          userName: response.user?.userName,
          email: response.user?.email,
          role: response.user?.role
        };

        localStorage.setItem('loginUser', JSON.stringify(loginUser));
        login(loginUser, response.access);

        if (response.access) {
          localStorage.setItem("accessToken", response.access);
        }

        if (response.refresh) {
          localStorage.setItem("refreshToken", response.refresh);
        }

        toast.success(response.message || "Login successful!");
        navigate("/");
        reset();
      }
    } catch (error: any) {
      console.error("Login error:", error);
      event?.preventDefault();

      let errorMessage = "Login failed. Please try again.";

      if (error.response?.data?.message) {
        errorMessage = error.response.data.message;
      } else if (error.message) {
        errorMessage = error.message;
      } else if (typeof error === 'string') {
        errorMessage = error;
      }

      if (errorMessage.toLowerCase().includes('invalid') ||
        errorMessage.toLowerCase().includes('wrong') ||
        errorMessage.toLowerCase().includes('incorrect') ||
        errorMessage.toLowerCase().includes('not found') ||
        errorMessage.toLowerCase().includes('credential')) {
        errorMessage = "Invalid username/email or password";
      }

      setLoginError(errorMessage);
      toast.error(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box sx={{ 
      minHeight: '100vh', 
      display: 'flex', 
      alignItems: 'center', 
      justifyContent: 'center',
      p: 2
    }}>
      <Paper elevation={0} sx={{ maxWidth: 450, width: '100%', p: 4, borderRadius: 1 }}>
        <Box sx={{ textAlign: 'center', mb: 4 }}>
          <Box
            sx={{
              width: 70,
              height: 70,
              borderRadius: '50%',
              // backgroundColor: 'primary.light',
              display: 'flex',
              border:1,
              alignItems: 'center',
              justifyContent: 'center',
              margin: '0 auto 20px',
              color: 'primary.main',
            }}
          >
            <LockOutlined sx={{ fontSize: 35 }} />
          </Box>
          <Typography variant="h4" fontWeight="bold" sx={{ mb: 1 }}>
            Welcome Back
          </Typography>
          <Typography variant="body2" color="text.secondary">
            Sign in to continue to your account
          </Typography>
        </Box>

        {loginError && (
          <Alert 
            severity="error" 
            sx={{ mb: 3, borderRadius: 1.5 }}
            onClose={() => setLoginError('')}
          >
            {loginError}
          </Alert>
        )}

        <form onSubmit={handleSubmit(onSubmit)}>
          <TextField
            fullWidth
            size="small"
            label="Username or Email"
            placeholder="Enter your username or email"
            error={!!errors.identifier}
            helperText={errors.identifier?.message}
            disabled={loading}
            sx={{ mb: 2.5 }}
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <PersonOutline color="action" fontSize="small" />
                </InputAdornment>
              ),
            }}
            {...register('identifier', {
              required: 'Username or Email is required',
              onChange: () => {
                if (loginError) setLoginError('');
              }
            })}
          />

          <TextField
            fullWidth
            size="small"
            label="Password"
            placeholder="Enter your password"
            type={showPassword ? 'text' : 'password'}
            error={!!errors.password}
            helperText={errors.password?.message}
            disabled={loading}
            sx={{ mb: 1.5 }}
            InputProps={{
              startAdornment: (
                <InputAdornment position="start">
                  <LockOutlined color="action" fontSize="small" />
                </InputAdornment>
              ),
              endAdornment: (
                <InputAdornment position="end">
                  <IconButton
                    onClick={() => setShowPassword((prev) => !prev)}
                    edge="end"
                    size="small"
                    disabled={loading}
                  >
                    {showPassword ? (
                      <VisibilityOff fontSize="small" />
                    ) : (
                      <Visibility fontSize="small" />
                    )}
                  </IconButton>
                </InputAdornment>
              ),
            }}
            {...register('password', {
              required: 'Password is required',
              minLength: { value: 6, message: 'Password must be at least 6 characters' },
              onChange: () => {
                if (loginError) setLoginError('');
              }
            })}
          />

          <Box
            width="100%"
            display="flex"
            alignItems="center"
            justifyContent="end"
            sx={{ mb: 3 }}
          >
            {/* <FormControlLabel
              control={<Checkbox size="small" disabled={loading} />}
              label={<Typography variant="body2">Remember me</Typography>}
            /> */}
            <Link 
              fontSize="small" 
              to="/forgot-password" 
              variant="body2" 
              color="text.secondary" 
              underline="hover"
              sx={{ fontWeight: 500 }}
            >
              Forgot password?
            </Link>
          </Box>

          <Button
            fullWidth
            size='small'
            type="submit"
            variant="contained"
            disabled={loading}
            sx={{ 
              py: 1.2, 
              textTransform: 'none', 
              mb: 2.5,
              fontWeight: 600,
              borderRadius: 1.5,
            }}
          >
            {loading ? (
              <CircularProgress size={24} color="inherit" />
            ) : (
              <>
                <LoginIcon sx={{ mr: 1, fontSize: 20 }} />
                Sign In
              </>
            )}
          </Button>

          {/* <Divider sx={{ mb: 2.5 }}>
            <Typography variant="caption" color="text.secondary">
              Don't have an account?
            </Typography>
          </Divider>

          <Button
            fullWidth
            variant="outlined"
            onClick={() => navigate('/register')}
            disabled={loading}
            sx={{ 
              textTransform: 'none',
              borderRadius: 1.5,
              py: 1,
            }}
          >
            Create New Account
          </Button> */}
        </form>
      </Paper>
    </Box>
  );
};

export default LoginForm;